def _seed_polity_ch77_notes_inner(conn, db_exec_fn, row_to_dict_fn, use_postgres=False, force=False):
    existing = row_to_dict_fn(
        db_exec_fn(conn, "SELECT id FROM study_notes WHERE topic='Indian_Polity' AND chapter_num=77").fetchone() or {}
    )
    if existing and not force:
        return
    if existing and force:
        db_exec_fn(conn, "DELETE FROM study_notes WHERE topic='Indian_Polity' AND chapter_num=77")
    ph = "%s" if use_postgres else "?"
    db_exec_fn(conn,
        f"INSERT INTO study_notes (subject, topic, chapter_num, title, content, summary) VALUES ({ph},{ph},{ph},{ph},{ph},{ph})",
        ("GK", "Indian_Polity", 77,
         "Special Provisions for Certain Classes",
         NOTES_HTML, SUMMARY_HTML)
    )

def _seed_polity_ch77_mcqs_inner(conn, db_exec_fn, row_to_dict_fn, use_postgres=False, force=False):
    existing = row_to_dict_fn(
        db_exec_fn(conn, "SELECT id FROM chapter_mcqs WHERE topic='Indian_Polity' AND chapter_num=77").fetchone() or {}
    )
    if existing and not force:
        return
    if existing and force:
        db_exec_fn(conn, "DELETE FROM chapter_mcqs WHERE topic='Indian_Polity' AND chapter_num=77")
    ph = "%s" if use_postgres else "?"
    sql = (f"INSERT INTO chapter_mcqs "
           f"(subject,topic,chapter_num,section_index,difficulty,question_telugu,"
           f"option_a,option_b,option_c,option_d,correct_option,explanation) "
           f"VALUES ({ph},{ph},{ph},{ph},{ph},{ph},{ph},{ph},{ph},{ph},{ph},{ph})")
    for sec_idx, diff, q_te, opt_a, opt_b, opt_c, opt_d, correct, explanation in _MCQ_DATA:
        db_exec_fn(conn, sql,
            ("GK", "Indian_Polity", 77, sec_idx, diff, q_te,
             opt_a, opt_b, opt_c, opt_d, correct, explanation))

def seed_polity_ch77(conn, db_exec_fn, row_to_dict_fn, use_postgres=False, force=False):
    _seed_polity_ch77_notes_inner(conn, db_exec_fn, row_to_dict_fn, use_postgres, force)
